  Widget _buildHorizontalList(
    List<Map<String, dynamic>> items, {
    required PageController snapController,
  }) {
    // When the user selects "one listing per row" (list layout),
    // render similar/related as a horizontal swipe list of full-width rows.
    if (_listingColumnsPref == 1) {
      return LayoutBuilder(
        builder: (context, constraints) {
          final double viewportW = constraints.maxWidth;
          final double itemW = (viewportW.isFinite && viewportW > 0)
              ? viewportW
              : MediaQuery.of(context).size.width;
          final double h = (itemW.isFinite && itemW > 0) ? (itemW / 2.78) : 140;

          return SizedBox(
            height: h,
            child: PageView.builder(
              controller: snapController,
              physics: const PageScrollPhysics(),
              pageSnapping: true,
              itemCount: items.length,
              itemBuilder: (context, index) {
                final item = Map<String, dynamic>.from(items[index]);
                final normalized = mapListingToGlobalCarCardData(context, item);
                return Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 2),
                  child: SizedBox(
                    width: itemW,
                    height: h,
                    child: buildGlobalCarCard(
                      context,
                      normalized,
                      listLayout: true,
                    ),
                  ),
                );
              },
            ),
          );
        },
      );
    }

    // Default: keep the horizontal carousel in grid-card style.
    return SizedBox(
      height: 320,
      child: ListView.separated(
        padding: const EdgeInsets.symmetric(horizontal: 2),
        scrollDirection: Axis.horizontal,
        itemCount: items.length,
        separatorBuilder: (_, __) => SizedBox(width: 12),
        itemBuilder: (context, index) {
          final item = Map<String, dynamic>.from(items[index]);
          final normalized = mapListingToGlobalCarCardData(context, item);
          return SizedBox(
            width: 200,
            child: AspectRatio(
              // Match Home grid card aspect ratio so layout doesn't overflow.
              aspectRatio: 0.72,
              child: buildGlobalCarCard(context, normalized),
            ),
          );
        },
      ),
    );
  }

  Widget _buildSmallCarCard(Map<String, dynamic> data) {
    final isLight = Theme.of(context).brightness == Brightness.light;
    return InkWell(
      onTap: () {
        // Analytics tracking for view listing
        Navigator.pushNamed(
          context,
          '/car_detail',
          arguments: {'carId': data['id']},
        );
      },
      child: Container(
        width: 160,
        decoration: BoxDecoration(
          color: isLight
              ? AppThemes.listingCardFillCompactOnLightShell()
              : Colors.white.withOpacity(0.08),
          borderRadius: BorderRadius.circular(12),
          border: Border.all(color: Colors.white12),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            ClipRRect(
              borderRadius: BorderRadius.vertical(top: Radius.circular(12)),
              child: () {
                final String primary = (data['image_url'] ?? '').toString();
                final List<dynamic> imgs = (data['images'] is List)
                    ? (data['images'] as List)
                    : const [];
                final String rel = primary.isNotEmpty
                    ? primary
                    : (imgs.isNotEmpty ? imgs.first.toString() : '');
                if (rel.isNotEmpty) {
                  final built = _buildFullImageUrl(rel);
                  return _listingNetworkImage(
                    built,
                    height: 110,
                    width: 160,
                    fit: BoxFit.cover,
                  );
                }
                return Container(
                  height: 110,
                  width: 160,
                  color: Colors.black26,
                  child: Icon(Icons.directions_car, color: Colors.white38),
                );
              }(),
            ),
            Padding(
              padding: const EdgeInsets.fromLTRB(
                8.0,
                16.0,
                8.0,
                8.0,
              ), // Much more padding at top for space between image and text
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    data['title']?.toString() ?? '',
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    style: const TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                  SizedBox(height: 8),
                  if (data['price'] != null)
                    Text(
                      _formatCurrencyGlobal(context, data['price']),
                      style: TextStyle(
                        color: Color(0xFFFF6B00),
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _spec(String label, String? value) {
