        borderRadius: BorderRadius.circular(12),
        border: Border.all(
          color: onTap != null
              ? const Color(0xFFFF6B00).withOpacity(isLight ? 0.34 : 0.42)
              : (isLight ? const Color(0xFFE0E0E0) : Colors.white12),
          width: onTap != null ? 1.2 : 1,
