              decoration: BoxDecoration(
                color: Color(0xFFFF6B00),
                borderRadius: BorderRadius.circular(999),
              ),
              child: Text(
                value!,
                style: TextStyle(
                  color: Colors.black,
                  fontWeight: FontWeight.w800,
                  fontSize: 12,
                ),
              ),
            ),
        ],
      ),
    );
    if (onTap == null) return content;
    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(12),
        onTap: onTap,
        child: content,
      ),
    );
  }

  Widget specCard(_SpecItem item) {
    return Container(
      padding: EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      decoration: BoxDecoration(
        color: Color(0xFFFF6B00),
        borderRadius: BorderRadius.circular(12),
      ),
      child: LayoutBuilder(
        builder: (context, constraints) {
          final double labelFontSize =
              (constraints.maxWidth * 0.13).clamp(9.0, 11.0);
          final double valueFontSize =
              (constraints.maxWidth * 0.16).clamp(10.0, 14.0);

          final labelStyle = TextStyle(
            fontSize: labelFontSize,
            color: Colors.black87,
            fontWeight: FontWeight.w700,
            letterSpacing: 0.3,
            height: 1.05,
          );
          final valueStyle = TextStyle(
            fontSize: valueFontSize,
            height: 1.0,
            color: Colors.black,
            fontWeight: FontWeight.w800,
          );

          return Column(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              Expanded(
                flex: 6,
                child: Center(
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    mainAxisAlignment: MainAxisAlignment.center,
                    crossAxisAlignment: CrossAxisAlignment.center,
                    children: [
                      Icon(
                        item.icon,
                        size: constraints.maxWidth * 0.13,
                        color: Colors.black87,
                      ),
                      const SizedBox(width: 4),
                      ConstrainedBox(
                        constraints: BoxConstraints(
                          maxWidth:
                              constraints.maxWidth - (constraints.maxWidth * 0.13) - 4,
                        ),
                        child: AutoSizeText(
                          item.label,
                          maxLines: 1,
                          textAlign: TextAlign.center,
                          softWrap: false,
                          textScaleFactor: 1.0,
                          style: labelStyle,
                          minFontSize: 7,
                          stepGranularity: 0.5,
                          overflow: TextOverflow.clip,
                        ),
                      ),
                    ],
                  ),
                ),
              ),
              Padding(
                padding: EdgeInsets.symmetric(
                  vertical: math.max(3.0, constraints.maxHeight * 0.02),
                  horizontal: 6,
                ),
                child: Divider(
                  height: 1,
                  thickness: 1,
                  color: Colors.black.withOpacity(0.22),
                ),
              ),
              Expanded(
                flex: 5,
                child: Center(
                  child: AutoSizeText(
                    item.value!,
                    maxLines: 1,
                    textAlign: TextAlign.center,
                    textScaleFactor: 1.0,
                    style: valueStyle,
                    minFontSize: 9,
                    stepGranularity: 0.5,
                    overflow: TextOverflow.clip,
                  ),
                ),
              ),
            ],
          );
        },
      ),
    );
  }

  final String mileageVal = car['mileage'] != null
      ? '${_localizeDigitsGlobal(context, formatNumericLabel(car['mileage'].toString()))} ${AppLocalizations.of(context)!.unit_km}'
      : '—';

  final String? transRaw = pickNE(car, ['transmission']);
  final String transmissionVal = _orDash(
    _translateValueGlobal(context, transRaw) ?? transRaw,
  );

  final String? engineSizePrimary = pickNE(car, [
    'engine_size',
    'engine_size_liters',
    'engine_size_l',
    'engineSize',
    'engineSizeLiters',
    'engine',
  ]) ??
      () {
        final dynamic specsRaw = car['specs'] ?? car['spec'] ?? car['details'];
        if (specsRaw is Map) {
          final specs = Map<String, dynamic>.from(specsRaw as Map);
          return pickNE(specs, [
            'engine_size',
            'engine_size_liters',
            'engine_size_l',
            'engineSize',
            'engineSizeLiters',
            'engine',
          ]);
        }
        return null;
      }();
  final String engineCardVal = () {
    final raw = engineSizePrimary?.toString().trim() ?? '';
    if (raw.isEmpty) return '—';
    final eng = OnlineSpecVariant.parseLeadingEngineLiters(raw) ??
        double.tryParse(raw);
    if (eng != null && eng > 0) {
      return '${_localizeDigitsGlobal(context, eng.toStringAsFixed(1))}${AppLocalizations.of(context)!.unit_liter_suffix}';
    }
    return _localizeDigitsGlobal(context, raw);
  }();

  final String? cylRawPrimary = pickNE(car, [
    'cylinder_count',
    'cylinders',
    'cylinderCount',
  ]);
  final String cylinderVal = cylRawPrimary != null
      ? _localizeDigitsGlobal(context, cylRawPrimary)
      : '—';

  final String titleStatusVal = _orDash(
    car['title_status'] != null
        ? (car['title_status'].toString().toLowerCase() == 'damaged'
              ? (car['damaged_parts'] != null
                    ? AppLocalizations.of(context)!.titleStatusDamagedWithParts(
                        _localizeDigitsGlobal(
                          context,
                          car['damaged_parts'].toString(),
                        ),
                      )
                    : AppLocalizations.of(context)!.value_title_damaged)
              : AppLocalizations.of(context)!.value_title_clean)
        : null,
  );

  final String? fuelRaw = pickNE(car, ['fuel_type', 'fuelType', 'fuel']);
  final String fuelVal = _orDash(
    _translateValueGlobal(context, fuelRaw) ?? fuelRaw,
  );

  final List<_SpecItem> primary = [
    _SpecItem(
      icon: Icons.speed,
      label: AppLocalizations.of(context)!.mileageLabel,
      value: mileageVal,
    ),
    _SpecItem(
      icon: Icons.settings_input_component,
      label: AppLocalizations.of(context)!.detail_cylinders,
      value: cylinderVal,
    ),
    _SpecItem(
      icon: Icons.straighten,
      label: AppLocalizations.of(context)!.detail_engine,
      value: engineCardVal,
    ),
    _SpecItem(
      icon: Icons.public,
      label: AppLocalizations.of(context)!.regionSpecsLabel,
      value: _orDash(() {
        final raw = pickNE(car, ['region_specs', 'regionSpecs']) ?? '';
        final c = raw.toString().trim().toLowerCase();
        if (!isValidCarRegionSpecCode(c)) return '';
        return carRegionSpecDisplayLabel(c);
      }()),
    ),
    _SpecItem(
      icon: Icons.settings,
      label: AppLocalizations.of(context)!.transmissionLabel,
      value: transmissionVal,
    ),
    _SpecItem(
      icon: Icons.local_gas_station,
      label: AppLocalizations.of(context)!.detail_fuel,
      value: fuelVal,
    ),
  ];

  final List<Widget> details = [
    detailRowSpec(
      icon: Icons.layers,
      label: AppLocalizations.of(context)!.trimLabel,
      value: _orDash(
        _translateValueGlobal(context, pickNE(car, ['trim'])) ??
            pickNE(car, ['trim']),
      ),
    ),
    detailRowSpec(
      icon: Icons.check_circle,
      label: AppLocalizations.of(context)!.detail_condition,
      value: _orDash(
        _translateValueGlobal(context, pickNE(car, ['condition'])),
      ),
    ),
    detailRowSpec(
      icon: Icons.assignment_turned_in,
      label: AppLocalizations.of(context)!.titleStatus,
      value: titleStatusVal,
    ),
    detailRowSpec(
      icon: Icons.drive_eta,
      label: AppLocalizations.of(context)!.detail_drive,
      value: _orDash(
        _translateValueGlobal(
          context,
          pickNE(car, ['drive_type', 'driveType', 'drivetrain', 'drive']),
        ),
      ),
    ),
    detailRowSpec(
      icon: Icons.directions_car_filled,
      label: AppLocalizations.of(context)!.detail_body,
      value: _orDash(
        _translateValueGlobal(
          context,
          pickNE(car, ['body_type', 'bodyType', 'body']),
        ),
      ),
    ),
    detailRowSpec(
      icon: Icons.color_lens,
      label: AppLocalizations.of(context)!.detail_color,
      value: _orDash(_translateValueGlobal(context, pickNE(car, ['color']))),
    ),
    detailRowSpec(
      icon: Icons.airline_seat_recline_normal,
      label: AppLocalizations.of(context)!.detail_seating,
      value: _orDash(
        _localizeDigitsGlobal(
          context,
          pickNE(car, ['seating', 'seats', 'seatCount']) ?? '',
        ),
      ),
    ),
    detailRowSpec(
      icon: Icons.confirmation_number_outlined,
      label: _trLegacyText(
        context,
        'Plate',
        ar: 'اللوحة',
        ku: 'پڵەیت',
      ),
      value: _orDash(() {
        final rawCity = pickNE(car, ['plate_city', 'plateCity'])?.trim();
        final rawType = pickNE(car, ['plate_type', 'plateType'])?.trim();

        final String? city = (rawCity == null || rawCity.isEmpty)
            ? null
            : (_translateValueGlobal(context, rawCity) ?? rawCity);
        final String? type = (rawType == null || rawType.isEmpty)
            ? null
            : _translatePlateTypeLegacy(context, rawType);

        if (city == null && type == null) return null;
        if (city != null && type != null) return '$city/$type';
        return city ?? type;
      }()),
    ),
  ];
  final description = pickNE(car, ['description'])?.trim() ?? '';
  if (description.isNotEmpty) {
    details.add(
      detailRowSpec(
        icon: Icons.description_outlined,
        label: AppLocalizations.of(context)?.descriptionTitle ?? 'Description',
        value: _trLegacyText(
          context,
          'View description',
          ar: 'عرض الوصف',
          ku: 'پیشاندانی وەسف',
        ),
        onTap: () {
          showDialog<void>(
            context: context,
            builder: (dialogContext) => AlertDialog(
              title: Text(
                AppLocalizations.of(context)?.descriptionTitle ?? 'Description',
              ),
              content: SingleChildScrollView(child: Text(description)),
              actions: [
                TextButton(
                  onPressed: () => Navigator.pop(dialogContext),
                  child: Text(
                    _trLegacyText(
                      context,
                      'Close',
                      ar: 'إغلاق',
                      ku: 'داخستن',
                    ),
                  ),
                ),
              ],
            ),
          );
        },
      ),
    );
  }

  final isLightSpecs = Theme.of(context).brightness == Brightness.light;
  // Width-based row height: tighter than childAspectRatio 1.5 so the outer
  // shell does not grow vertically on narrow phones (GridView + padding).
  final primGrid = LayoutBuilder(
    builder: (context, constraints) {
      const double crossGap = 12;
      const int crossCount = 3;
      final double maxW = constraints.maxWidth;
      final double tileW = (maxW - crossGap * (crossCount - 1)) / crossCount;
      // Was ~1.5 (height = tileW/1.5); 1.72 shortens each row ~13%.
      final double rowH = tileW / 1.72;
      return GridView.builder(
        shrinkWrap: true,
        physics: const NeverScrollableScrollPhysics(),
        padding: EdgeInsets.zero,
        gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
          crossAxisCount: crossCount,
          crossAxisSpacing: crossGap,
          mainAxisSpacing: 12,
          mainAxisExtent: rowH,
        ),
        itemCount: primary.length,
        itemBuilder: (context, index) => specCard(primary[index]),
      );
    },
  );

  final topSpecs = Container(
    width: double.infinity,
    padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
    decoration: BoxDecoration(
      color: isLightSpecs
          ? const Color(0xFFEEEEEE)
          : Colors.white.withOpacity(0.08),
      borderRadius: BorderRadius.circular(14),
      border: Border.all(
        color: isLightSpecs ? const Color(0xFFE0E0E0) : Colors.white24,
      ),
    ),
    child: primGrid,
  );

  return Column(
    crossAxisAlignment: CrossAxisAlignment.start,
    children: [topSpecs, SizedBox(height: 12), ...details],
  );
}

class _SpecItem {
  final IconData icon;
  final String label;
  final String? value;
  final bool isSecondary;
  _SpecItem({
    required this.icon,
    required this.label,
    required this.value,
    this.isSecondary = false,
  });
}

const String _sellDraftArchiveKey = 'legacy_sell_draft_archive_v1';

String _newSellDraftId() => DateTime.now().microsecondsSinceEpoch.toString();

Map<String, dynamic> _normalizeSellDraftSnapshot(Map<String, dynamic> raw) {
  final rawCarData = raw['carData'];
  final carData = rawCarData is Map
      ? Map<String, dynamic>.from(rawCarData.cast<String, dynamic>())
      : <String, dynamic>{};
  final draftId = (raw['draftId'] ?? '').toString().trim();
  return <String, dynamic>{
    'draftId': draftId.isEmpty ? _newSellDraftId() : draftId,
    'currentStep': int.tryParse(raw['currentStep']?.toString() ?? '') ?? 0,
    'carData': carData,
    'isPlaceholder': raw['isPlaceholder'] == true,
    'updatedAt': raw['updatedAt'] ?? DateTime.now().millisecondsSinceEpoch,
  };
}

List<Map<String, dynamic>> _decodeSellDraftArchive(String? raw) {
  if (raw == null || raw.trim().isEmpty) return <Map<String, dynamic>>[];
  try {
    final decoded = json.decode(raw);
    if (decoded is! List) return <Map<String, dynamic>>[];
    return decoded
        .whereType<Map>()
        .map(
          (item) => _normalizeSellDraftSnapshot(
            Map<String, dynamic>.from(item.cast<String, dynamic>()),
          ),
        )
        .toList();
  } catch (_) {
    return <Map<String, dynamic>>[];
  }
}

String _encodeSellDraftArchive(List<Map<String, dynamic>> drafts) {
  return json.encode(
    drafts.map((draft) => _normalizeSellDraftSnapshot(draft)).toList(),
  );
}

bool _hasMeaningfulSellDraftValue(dynamic value) {
  if (value == null) return false;
  if (value is String) return value.trim().isNotEmpty;
  if (value is num) return value != 0;
  if (value is bool) return value;
  if (value is XFile) return value.path.trim().isNotEmpty;
  if (value is Map) {
    for (final entry in value.entries) {
      if (_hasMeaningfulSellDraftValue(entry.value)) return true;
    }
    return false;
  }
  if (value is Iterable) {
    for (final item in value) {
      if (_hasMeaningfulSellDraftValue(item)) return true;
    }
    return false;
  }
  return value.toString().trim().isNotEmpty;
}

bool _isVisibleSellDraft(Map<String, dynamic> draft) {
  return _hasMeaningfulSellDraftValue(draft['carData']);
}

class SellEntryRouterPage extends StatefulWidget {
  const SellEntryRouterPage({super.key});

  @override
  State<SellEntryRouterPage> createState() => _SellEntryRouterPageState();
}

class _SellEntryRouterPageState extends State<SellEntryRouterPage> {
  static const String _draftSnapshotKey = 'legacy_sell_draft_snapshot_v1';
  static const String _sellDraftArchiveKey = 'legacy_sell_draft_archive_v1';

  Future<void> _resolve() async {
    try {
      final sp = await SharedPreferences.getInstance();
      final activeRaw = sp.getString(_draftSnapshotKey);
      final archive = _decodeSellDraftArchive(sp.getString(_sellDraftArchiveKey));
      bool hasAnyDraft = false;
      if (activeRaw != null && activeRaw.trim().isNotEmpty) {
        final decoded = json.decode(activeRaw);
        if (decoded is Map) {
          final active = _normalizeSellDraftSnapshot(
            Map<String, dynamic>.from(decoded.cast<String, dynamic>()),
          );
          hasAnyDraft = _isVisibleSellDraft(active);
        }
      }
      hasAnyDraft = hasAnyDraft || archive.any(_isVisibleSellDraft);
      if (!mounted) return;
      Navigator.pushReplacementNamed(
        context,
        '/sell',
        arguments: hasAnyDraft ? {'showDraftGate': true} : {'startFresh': true},
      );
    } catch (_) {
      if (!mounted) return;
      Navigator.pushReplacementNamed(
        context,
        '/sell',
        arguments: {'startFresh': true},
      );
    }
  }

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) unawaited(_resolve());
    });
  }

  @override
  Widget build(BuildContext context) {
    return const Scaffold(
      body: Center(
        child: CircularProgressIndicator(),
      ),
    );
  }
}

class SellDraftGatePage extends StatefulWidget {
  const SellDraftGatePage({super.key});

  @override
  State<SellDraftGatePage> createState() => _SellDraftGatePageState();
}

class _SellDraftGatePageState extends State<SellDraftGatePage> {
  static const String _draftSnapshotKey = 'legacy_sell_draft_snapshot_v1';
  bool _loading = true;
  List<Map<String, dynamic>> _drafts = <Map<String, dynamic>>[];

  void _goBack() {
    if (Navigator.of(context).canPop()) {
      Navigator.of(context).pop();
    } else {
      Navigator.pushReplacementNamed(context, '/');
    }
  }

  String _draftTitle(Map<String, dynamic> data) {
    final brand = (data['brand'] ?? '').toString().trim();
    final model = (data['model'] ?? '').toString().trim();
    final trim = (data['trim'] ?? '').toString().trim();
    final year = (data['year'] ?? '').toString().trim();
    final title = [brand, model].where((v) => v.isNotEmpty).join(' ');
    final suffix = [trim, year].where((v) => v.isNotEmpty).join(' • ');
    if (title.isEmpty && suffix.isEmpty) return 'Untitled draft';
    if (title.isEmpty) return suffix;
    if (suffix.isEmpty) return title;
    return '$title • $suffix';
  }

  Future<void> _loadDrafts() async {
    try {
      final sp = await SharedPreferences.getInstance();
      final activeRaw = sp.getString(_draftSnapshotKey);
      final archive = _decodeSellDraftArchive(sp.getString(_sellDraftArchiveKey));

      final drafts = <Map<String, dynamic>>[];
      final seenIds = <String>{};
      if (activeRaw != null && activeRaw.trim().isNotEmpty) {
        try {
          final decoded = json.decode(activeRaw);
          if (decoded is Map) {
            final active = _normalizeSellDraftSnapshot(
              Map<String, dynamic>.from(decoded.cast<String, dynamic>()),
            );
            if (_isVisibleSellDraft(active)) {
              drafts.add(<String, dynamic>{...active, 'isActive': true});
              seenIds.add(active['draftId'].toString());
            }
          }
        } catch (_) {}
      }
      for (final draft in archive) {
        if (!_isVisibleSellDraft(draft)) continue;
        final id = draft['draftId'].toString();
        if (seenIds.contains(id)) continue;
        drafts.add(<String, dynamic>{...draft, 'isActive': false});
        seenIds.add(id);
      }

      if (!mounted) return;
      setState(() {
        _drafts = drafts;
        _loading = false;
      });
      if (_drafts.isEmpty) {
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (mounted) _startFresh();
        });
      }
    } catch (_) {
      if (!mounted) return;
      setState(() {
        _drafts = <Map<String, dynamic>>[];
        _loading = false;
      });
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (mounted) _startFresh();
      });
    }
  }

  Future<void> _archiveActiveDraftIfAny({bool clearActive = true}) async {
    try {
      final sp = await SharedPreferences.getInstance();
      final activeRaw = sp.getString(_draftSnapshotKey);
      if (activeRaw != null && activeRaw.trim().isNotEmpty) {
        final decoded = json.decode(activeRaw);
        if (decoded is Map) {
          final active = _normalizeSellDraftSnapshot(
            Map<String, dynamic>.from(decoded.cast<String, dynamic>()),
          );
          if (_isVisibleSellDraft(active)) {
            final archive =
                _decodeSellDraftArchive(sp.getString(_sellDraftArchiveKey));
            archive.removeWhere((draft) => draft['draftId'] == active['draftId']);
            archive.insert(0, active);
            await sp.setString(
              _sellDraftArchiveKey,
              _encodeSellDraftArchive(archive),
            );
          }
        }
      }
      if (clearActive) {
        await sp.remove(_draftSnapshotKey);
        await sp.remove('legacy_sell_draft_current_step_v1');
        await sp.remove('legacy_sell_draft_step1_v1');
        await sp.remove('legacy_sell_draft_step2_v1');
        await sp.remove('legacy_sell_draft_step3_v1');
        await sp.remove('legacy_sell_draft_step4_v1');
      }
    } catch (_) {}
  }

  Future<void> _discardDraft(Map<String, dynamic> draft) async {
    final draftId = (draft['draftId'] ?? '').toString();
    final isActive = draft['isActive'] == true;
    try {
      final sp = await SharedPreferences.getInstance();
      if (isActive) {
        await sp.remove(_draftSnapshotKey);
        await sp.remove('legacy_sell_draft_current_step_v1');
        await sp.remove('legacy_sell_draft_step1_v1');
        await sp.remove('legacy_sell_draft_step2_v1');
        await sp.remove('legacy_sell_draft_step3_v1');
        await sp.remove('legacy_sell_draft_step4_v1');
      } else {
        final archive =
            _decodeSellDraftArchive(sp.getString(_sellDraftArchiveKey));
        archive.removeWhere((item) => item['draftId'] == draftId);
        await sp.setString(_sellDraftArchiveKey, _encodeSellDraftArchive(archive));
      }
      if (!mounted) return;
      setState(() {
        _drafts.removeWhere((item) => item['draftId'] == draftId);
      });
      if (_drafts.isEmpty) {
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (mounted) _startFresh();
        });
      }
    } catch (_) {}
  }

  void _startFresh() {
    Navigator.pushReplacementNamed(
      context,
      '/sell',
      arguments: {'startFresh': true},
    );
  }

  Future<void> _startFreshWithArchive() async {
    await _archiveActiveDraftIfAny(clearActive: false);
    if (!mounted) return;
    _startFresh();
  }

  Future<void> _continueDraft(Map<String, dynamic> draft) async {
    final normalized = _normalizeSellDraftSnapshot(draft);
    final isActive = draft['isActive'] == true;
    if (!isActive) {
      await _archiveActiveDraftIfAny(clearActive: false);
      try {
        final sp = await SharedPreferences.getInstance();
        final archive =
            _decodeSellDraftArchive(sp.getString(_sellDraftArchiveKey));
        archive.removeWhere((item) => item['draftId'] == normalized['draftId']);
        await sp.setString(_sellDraftArchiveKey, _encodeSellDraftArchive(archive));
        await sp.setString(_draftSnapshotKey, json.encode(normalized));
      } catch (_) {}
    }
    if (!mounted) return;
    Navigator.pushReplacementNamed(
      context,
      '/sell',
      arguments: {'draftSnapshot': normalized},
    );
  }

  Widget _buildDraftCard(Map<String, dynamic> draft) {
    final carData = draft['carData'] is Map
        ? Map<String, dynamic>.from((draft['carData'] as Map).cast<String, dynamic>())
        : <String, dynamic>{};
    final currentStep = int.tryParse(draft['currentStep']?.toString() ?? '') ?? 0;
    final labels = <String>[
      _trLegacyText(context, 'Step 1: Basic info', ar: 'الخطوة 1: المعلومات الأساسية', ku: 'هەنگاو 1: زانیاری سەرەکی'),
      _trLegacyText(context, 'Step 2: Details', ar: 'الخطوة 2: التفاصيل', ku: 'هەنگاو 2: وردەکاری'),
      _trLegacyText(context, 'Step 3: Pricing', ar: 'الخطوة 3: السعر', ku: 'هەنگاو 3: نرخ'),
      _trLegacyText(context, 'Step 4: Photos', ar: 'الخطوة 4: الصور', ku: 'هەنگاو 4: وێنەکان'),
      _trLegacyText(context, 'Step 5: Review', ar: 'الخطوة 5: المراجعة', ku: 'هەنگاو 5: پێداچوونەوە'),
    ];
    final label = labels[currentStep.clamp(0, 4).toInt()];
    final title = _draftTitle(carData);
    final isActive = draft['isActive'] == true;

    return Container(
      margin: const EdgeInsets.only(bottom: 12),
      decoration: BoxDecoration(
        color: Colors.orange.withOpacity(0.08),
        borderRadius: BorderRadius.circular(18),
        border: Border.all(color: Colors.orange.withOpacity(0.24)),
      ),
      child: Padding(
        padding: const EdgeInsets.all(14),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Container(
                  width: 42,
                  height: 42,
                  decoration: BoxDecoration(
                    color: const Color(0xFFFF6B00).withOpacity(0.12),
                    borderRadius: BorderRadius.circular(12),
                  ),
                  child: const Icon(Icons.drafts_outlined, color: Color(0xFFFF6B00)),
