                              return l.pleaseSelectEngineSize;
                            }
                            final size = double.tryParse(value);
                            if (size == null) return l.pleaseSelectEngineSize;
                            if (size <= 0) {
                              return l.pleaseSelectEngineSize;
                            }
                            return null;
