                                                children: [
                                                  Container(
                                                    height: 110,
                                                    width: 110,
                                                    decoration: BoxDecoration(
                                                      borderRadius:
                                                          BorderRadius.circular(
                                                            8,
                                                          ),
                                                      border: Border.all(
                                                        color: Colors.white10,
                                                      ),
                                                    ),
                                                    child: ClipRRect(
                                                      borderRadius:
                                                          BorderRadius.circular(
                                                            8,
                                                          ),
                                                      child: _buildCarImage(
                                                        car,
                                                      ),
                                                    ),
                                                  ),
                                                  SizedBox(height: 8),
                                                  SizedBox(
                                                    height: headerTitleHeight,
                                                    child: Center(
                                                      child: AutoSizeText(
                                                        [
                                                              _localizedCarTitleForCard(
                                                                context,
                                                                car,
                                                              ),
                                                              _localizedTrimForCard(
                                                                context,
                                                                car,
                                                              ),
                                                            ]
                                                            .where(
                                                              (s) =>
                                                                  s.isNotEmpty,
                                                            )
                                                            .join(' '),
                                                        textScaleFactor: 1.0,
                                                        style: TextStyle(
                                                          fontWeight:
                                                              FontWeight.bold,
                                                          fontSize: 14,
                                                          color: isDark
                                                              ? Colors.white
                                                              : lightInk,
                                                          height: 1.15,
                                                        ),
                                                        textAlign:
                                                            TextAlign.center,
                                                        maxLines: 2,
                                                        minFontSize: 9,
                                                        stepGranularity: 0.5,
                                                        overflow:
                                                            TextOverflow.clip,
                                                        softWrap: true,
                                                      ),
                                                    ),
                                                  ),
                                                  SizedBox(height: 4),
                                                  SizedBox(
                                                    height: headerPriceHeight,
                                                    child: Center(
                                                      child: Text(
                                                        _formatCurrencyGlobal(
                                                          context,
                                                          car['price']
                                                                  ?.toString() ??
                                                              '0',
                                                        ),
                                                        style: TextStyle(
                                                          color: Color(
                                                            0xFFFF6B00,
                                                          ),
                                                          fontWeight:
                                                              FontWeight.bold,
                                                          fontSize: 16,
                                                        ),
                                                      ),
                                                    ),
                                                  ),
                                                  SizedBox(height: 8),
                                                  IconButton(
                                                    onPressed: () {
                                                      comparisonStore
                                                          .removeCarFromComparison(
                                                            car['id'],
                                                          );
                                                    },
                                                    icon: Icon(
                                                      Icons.close,
                                                      color: Colors.red,
                                                      size: 24,
                                                    ),
                                                    constraints:
                                                        BoxConstraints(),
                                                    padding: EdgeInsets.zero,
                                                  ),
                                                ],
                                              ),
                                            ),
                                          ),
                                        ),
                                      ],
                              ),
                            ),
                            SizedBox(height: 12),

                            // Comparison Rows
                            ..._buildComparisonRows(
                              context,
                              cars,
                              columnWidth,
                              labelWidth,
                            ),
                          ],
                        ),
                      );

                      if (isTwoCars) {
                        return SizedBox(width: availableWidth, child: table);
                      }
                      return SingleChildScrollView(
                        scrollDirection: Axis.horizontal,
                        physics: BouncingScrollPhysics(),
                        child: SizedBox(width: tableWidth, child: table),
                      );
                    },
                  ),
                ],
              );
            },
          ),
        ],
      ),
    );
  }

  Widget _buildCarImage(Map<String, dynamic> car) {
    final imageUrl = car['image_url']?.toString();
    if (imageUrl != null && imageUrl.isNotEmpty) {
      final built = _buildFullImageUrl(imageUrl);
      return _listingNetworkImage(built, fit: BoxFit.cover);
    }
    return Container(
      color: Colors.white10,
      child: Icon(Icons.directions_car, color: Colors.white24),
    );
  }

